Rule.Source:
  import sailpoint.object.Identity;
  import sailpoint.object.Link;
  import sailpoint.tools.Util;
  import sailpoint.object.Application;
  import sailpoint.api.IdentityService;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  static Log logger = LogFactory.getLog("rule.identityattributetarget.amita.manager");

  logger.debug("Entering Ascension-Rule-IdentityAttributeTarget-Amita-Manager");

  String managerDN = null; 
  List<Link> appLinks = null;
  Application app;
  //if link is disabled, dont pick the value from Identity
  if(null != link && link.isDisabled()){
	logger.debug("Picking value from disabled Link");
	managerDN = link.getAttribute(target.getName());
  }else	if(identity  != null){
    Identity managerObj=identity.getManager();
    if(null != managerObj){
      IdentityService idService = new IdentityService(context);   
      if(null != target && null != target.getApplication()){
        app = target.getApplication();	
      }

      if(null != app && !Util.isEmpty((appLinks = idService.getLinks( managerObj, app)))){
        for(Link applink : appLinks){
          if(!applink.isDisabled()){
            managerDN=applink.getNativeIdentity();
            break;
          }           
        }
      }                       
    }
  }

  logger.debug("Exiting Ascension-Rule-IdentityAttributeTarget-Amita-Manager");
  return managerDN;
